import React, { useState, useEffect } from 'react';
import { Link as RouterLink } from 'react-router-dom';
import {
  Box,
  Button,
  Container,
  Typography,
  Grid,
  Card,
  CardContent,
  Stack,
  Paper,
  useTheme,
  Avatar,
  Chip,
  Fade,
  Divider,
  IconButton,
  useMediaQuery,
  TextField,
  CircularProgress
} from '@mui/material';
import AutoAwesomeIcon from '@mui/icons-material/AutoAwesome';
import ArrowForwardIcon from '@mui/icons-material/ArrowForward';
import StarIcon from '@mui/icons-material/Star';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import PlayArrowIcon from '@mui/icons-material/PlayArrow';
import EmailIcon from '@mui/icons-material/Email';
import PersonIcon from '@mui/icons-material/Person';

const HomePage = () => {
  const theme = useTheme();
  const isMobile = useMediaQuery(theme.breakpoints.down('md'));

  // Interactive demo state
  const [demoStage, setDemoStage] = useState(0);
  const [demoInput, setDemoInput] = useState("The coaching was good. I learned some things that helped me.");
  const [isProcessing, setIsProcessing] = useState(false);
  const [enhancedText, setEnhancedText] = useState("");
  const [clientName, setClientName] = useState("");
  const [clientEmail, setClientEmail] = useState("");
  const [showApproval, setShowApproval] = useState(false);
  const [isApproved, setIsApproved] = useState(false);

  // Enhanced testimonial examples
  const enhancedExample = "Working with Sarah transformed my approach to challenges. I went from feeling stuck to landing two major clients in just 3 weeks. Her coaching didn't just teach me tactics—it changed my entire mindset about what's possible.";

  // Auto-advance demo stages
  useEffect(() => {
    if (demoStage === 0) {
      // Auto-start the demo after 2 seconds
      const timer = setTimeout(() => {
        handleEnhance();
      }, 2000);
      return () => clearTimeout(timer);
    }
  }, [demoStage]);

  const handleEnhance = () => {
    if (demoStage === 0) {
      setIsProcessing(true);
      // Simulate API processing
      setTimeout(() => {
        setEnhancedText(enhancedExample);
        setIsProcessing(false);
        setDemoStage(1);
      }, 2500);
    }
  };

  const handleSendApproval = () => {
    if (demoStage === 1) {
      setIsProcessing(true);
      // Simulate sending approval request
      setTimeout(() => {
        setIsProcessing(false);
        setDemoStage(2);
        setShowApproval(true);
      }, 1500);
    }
  };

  const handleApprove = () => {
    setIsApproved(true);
    // Simulate approval animation
    setTimeout(() => {
      setDemoStage(3);
    }, 1000);
  };

  const resetDemo = () => {
    setDemoStage(0);
    setIsProcessing(false);
    setEnhancedText("");
    setClientName("");
    setClientEmail("");
    setShowApproval(false);
    setIsApproved(false);
  };

  return (
    <Box sx={{ overflow: 'hidden' }}>
      {/* Hero Section */}
      <Box 
        sx={{
          pt: { xs: 8, md: 10 },
          pb: { xs: 10, md: 12 },
          position: 'relative',
        }}
      >
        {/* Background gradient */}
        <Box 
          sx={{
            position: 'absolute',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            background: 'linear-gradient(180deg, rgba(93, 95, 239, 0.05) 0%, rgba(93, 95, 239, 0) 100%)',
            zIndex: -1
          }}
        />

        <Container maxWidth="lg">
          <Grid container spacing={4} alignItems="center">
            <Grid item xs={12} md={6}>
              <Chip
                icon={<AutoAwesomeIcon />}
                label="AI-Powered Testimonials"
                sx={{ 
                  mb: 3, 
                  bgcolor: 'primary.light', 
                  color: 'primary.dark',
                  fontWeight: 600,
                  '& .MuiChip-icon': { color: 'primary.main' }
                }}
              />

              <Typography variant="h1" gutterBottom>
                Turn <Box component="span" sx={{ color: 'primary.main' }}>"It was good"</Box> into testimonials that sell
              </Typography>

              <Typography variant="subtitle1" color="text.secondary" sx={{ mb: 4, fontSize: '1.1rem' }}>
                Enhance bland client feedback into compelling stories that showcase your true impact—with AI that captures transformation, emotion, and results.
              </Typography>

              <Stack direction={{ xs: 'column', sm: 'row' }} spacing={2}>
                <Button 
                  variant="contained" 
                  color="primary"
                  size="large"
                  component={RouterLink}
                  to="/enhance"
                  sx={{ px: 3, py: 1.5 }}
                >
                  Enhance a Testimonial
                </Button>
                <Button 
                  variant="outlined" 
                  color="primary"
                  size="large"
                  startIcon={<PlayArrowIcon />}
                  sx={{ px: 3, py: 1.5 }}
                  onClick={resetDemo}
                >
                  See How It Works
                </Button>
              </Stack>

              <Box sx={{ display: 'flex', alignItems: 'center', mt: 4 }}>
                <Box sx={{ display: 'flex', mr: 2 }}>
                  {[...Array(5)].map((_, i) => (
                    <StarIcon key={i} sx={{ color: '#FFD700', fontSize: 20 }} />
                  ))}
                </Box>
                <Typography variant="body2" color="text.secondary">
                  <strong>4.9/5</strong> from 200+ users
                </Typography>
              </Box>
            </Grid>

            {/* Interactive Demo */}
            <Grid item xs={12} md={6}>
              <Card 
                elevation={0} 
                sx={{ 
                  borderRadius: 4,
                  border: '1px solid rgba(0, 0, 0, 0.08)',
                  overflow: 'hidden',
                  boxShadow: '0 10px 40px rgba(0, 0, 0, 0.1)',
                  height: 480,
                  position: 'relative',
                  transition: 'all 0.3s ease'
                }}
              >
                {/* Demo UI */}
                {!showApproval ? (
                  <Box sx={{ p: 3, height: '100%', display: 'flex', flexDirection: 'column' }}>
                    <Box sx={{ mb: 2, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                      <Typography variant="h6" fontWeight={600}>
                        {demoStage === 0 ? 'Enter Client Testimonial' : 
                         demoStage === 1 ? 'Enhanced Testimonial' : 
                         'Send for Approval'}
                      </Typography>
                      <Chip 
                        label={`Step ${demoStage + 1}/3`} 
                        size="small" 
                        sx={{ bgcolor: 'primary.light', color: 'primary.dark' }}
                      />
                    </Box>

                    <Divider sx={{ mb: 3 }} />

                    {demoStage === 0 && (
                      <Fade in={demoStage === 0}>
                        <Box sx={{ flex: 1, display: 'flex', flexDirection: 'column' }}>
                          <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
                            Paste your client's original testimonial:
                          </Typography>
                          <TextField
                            multiline
                            rows={6}
                            fullWidth
                            variant="outlined"
                            value={demoInput}
                            onChange={(e) => setDemoInput(e.target.value)}
                            placeholder="Example: The coaching was good. I learned some things that helped me."
                            sx={{ mb: 3 }}
                          />
                          <Box sx={{ mt: 'auto' }}>
                            <Button 
                              variant="contained" 
                              color="primary"
                              fullWidth
                              size="large"
                              onClick={handleEnhance}
                              disabled={isProcessing}
                              sx={{ py: 1.5 }}
                            >
                              {isProcessing ? (
                                <CircularProgress size={24} color="inherit" />
                              ) : (
                                <>Enhance Testimonial <AutoAwesomeIcon sx={{ ml: 1 }} /></>
                              )}
                            </Button>
                          </Box>
                        </Box>
                      </Fade>
                    )}

                    {demoStage === 1 && (
                      <Fade in={demoStage === 1}>
                        <Box sx={{ flex: 1, display: 'flex', flexDirection: 'column' }}>
                          <Box sx={{ mb: 3 }}>
                            <Typography variant="body2" color="text.secondary" gutterBottom>
                              Original:
                            </Typography>
                            <Paper 
                              elevation={0} 
                              sx={{ 
                                p: 2, 
                                bgcolor: 'grey.50',
                                borderRadius: 2
                              }}
                            >
                              <Typography variant="body2">{demoInput}</Typography>
                            </Paper>
                          </Box>

                          <Box sx={{ mb: 3 }}>
                            <Typography variant="body2" color="text.secondary" gutterBottom>
                              Enhanced:
                            </Typography>
                            <Paper 
                              elevation={0} 
                              sx={{ 
                                p: 2, 
                                bgcolor: 'primary.light',
                                borderRadius: 2
                              }}
                            >
                              <Typography variant="body2" color="primary.dark" fontWeight={500}>
                                {enhancedText}
                              </Typography>
                            </Paper>
                          </Box>

                          <Box sx={{ mt: 'auto' }}>
                            <Button 
                              variant="contained" 
                              color="primary"
                              fullWidth
                              size="large"
                              onClick={handleSendApproval}
                              disabled={isProcessing}
                              sx={{ py: 1.5 }}
                            >
                              {isProcessing ? (
                                <CircularProgress size={24} color="inherit" />
                              ) : (
                                <>Send for Client Approval <EmailIcon sx={{ ml: 1 }} /></>
                              )}
                            </Button>
                          </Box>
                        </Box>
                      </Fade>
                    )}

                    {demoStage === 2 && (
                      <Fade in={demoStage === 2}>
                        <Box sx={{ flex: 1, display: 'flex', flexDirection: 'column' }}>
                          <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
                            Enter client details to send approval request:
                          </Typography>

                          <TextField
                            fullWidth
                            variant="outlined"
                            label="Client Name"
                            value={clientName}
                            onChange={(e) => setClientName(e.target.value)}
                            placeholder="John Smith"
                            InputProps={{
                              startAdornment: <PersonIcon sx={{ mr: 1, color: 'text.secondary' }} />,
                            }}
                            sx={{ mb: 2 }}
                          />

                          <TextField
                            fullWidth
                            variant="outlined"
                            label="Client Email"
                            value={clientEmail}
                            onChange={(e) => setClientEmail(e.target.value)}
                            placeholder="john@example.com"
                            InputProps={{
                              startAdornment: <EmailIcon sx={{ mr: 1, color: 'text.secondary' }} />,
                            }}
                            sx={{ mb: 3 }}
                          />

                          <Box sx={{ mt: 'auto' }}>
                            <Button 
                              variant="contained" 
                              color="primary"
                              fullWidth
                              size="large"
                              onClick={() => setShowApproval(true)}
                              sx={{ py: 1.5 }}
                            >
                              Send Approval Request
                            </Button>
                          </Box>
                        </Box>
                      </Fade>
                    )}
                  </Box>
